{
var ringCount = Math.Max(1, GetInt(parameters, "ringCount", 6));
var cx = Math.Clamp(GetFloat(parameters, "centerX", 0.5f), 0.01f, 0.99f);
var cy = Math.Clamp(GetFloat(parameters, "centerY", 0.5f), 0.01f, 0.99f);
var thickness = GetFloat(parameters, "thickness", 0.5f);
var spacingMode = GetChoice(parameters, "spacingMode", "uniform");
var colorA = GetColor(parameters, "colorA", Colors.White);
var colorB = GetColor(parameters, "colorB", Colors.Black);
var distort = GetFloat(parameters, "distortion", 0f);
var softness = GetFloat(parameters, "softness", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var aR = colorA.R / 255f; var aG = colorA.G / 255f; var aB = colorA.B / 255f;
var bR = colorB.R / 255f; var bG = colorB.G / 255f; var bB = colorB.B / 255f;
var seed = GetInt(parameters, "seed", context.Seed);

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    var dx = u - cx;
    var dy = v - cy;
    var dist = MathF.Sqrt(dx * dx + dy * dy);

    // Normalize distance to max possible (corner)
    var maxDist = MathF.Sqrt(
        MathF.Max(cx, 1f - cx) * MathF.Max(cx, 1f - cx) +
        MathF.Max(cy, 1f - cy) * MathF.Max(cy, 1f - cy));
    var normDist = dist / maxDist;

    // Noise distortion
    if (distort > 0f)
    {
        var noiseVal = TileableFractalNoise(x * 0.5f, y * 0.5f, Math.Max(1, size / 2), 2, 0.5f, 2f, seed);
        normDist += (noiseVal - 0.5f) * distort * 0.3f;
        normDist = Math.Clamp(normDist, 0f, 1f);
    }

    // Ring pattern
    float ringPos;
    if (spacingMode == "logarithmic")
    {
        ringPos = MathF.Log(1f + normDist * 9f) / MathF.Log(10f) * ringCount;
    }
    else
    {
        ringPos = normDist * ringCount;
    }

    var local = ringPos - MathF.Floor(ringPos);
    var halfThick = thickness * 0.5f;
    var t = (local - (0.5f - halfThick)) / Math.Max(softness * 0.05f + 0.001f, 0.001f);
    t = Math.Clamp(t, 0f, 1f);

    if (invert) t = 1f - t;

    var r = Lerp(aR, bR, t);
    var g = Lerp(aG, bG, t);
    var b = Lerp(aB, bB, t);

    buffer.SetPixel(x, y, r, g, b, 1f);
});

return buffer;
}
